{"code": "import json
import pandas as pd
import re
import os

# Access all query result variables
all_vars = locals().keys()
query_vars = [var for var in all_vars if 'query_db' in var]

print(f"Found query variables: {query_vars}")

# Collect data from all sources
all_records = []
for var_name in query_vars:
    try:
        var_value = locals()[var_name]
        if isinstance(var_value, list) and len(var_value) > 0:
            all_records.extend(var_value)
            print(f"Added {len(var_value)} records from {var_name}")
        elif isinstance(var_value, str) and '.json' in var_value:
            if os.path.exists(var_value):
                with open(var_value, 'r') as f:
                    file_data = json.load(f)
                all_records.extend(file_data)
                print(f"Added {len(file_data)} records from file {var_value}")
    except Exception as e:
        print(f"Could not access {var_name}: {e}")

print(f"\nTotal records collected: {len(all_records)}")

# Function to extract month from grant date
def extract_month(grant_date):
    date_str = grant_date.lower()
    month_map = {
        'jul': 7, 'july': 7,
        'aug': 8, 'august': 8, 
        'sep': 9, 'september': 9, 'sept': 9,
        'oct': 10, 'october': 10,
        'nov': 11, 'november': 11,
        'dec': 12, 'december': 12
    }

    for pattern, month in month_map.items():
        if pattern in date_str:
            return month
    return None

# Filter for German patents in second half of 2019
german_patents = []
for record in all_records:
    try:
        patents_info = record.get('Patents_info', '')
        grant_date = record.get('grant_date', '')

        if patents_info and 'DE-' in patents_info and grant_date and '2019' in grant_date:
            month = extract_month(grant_date)
            if month and month >= 7:  # July to December
                german_patents.append(record)
    except:
        continue

print(f"German patents in second half 2019: {len(german_patents)}")

# Extract CPC level 4 codes
cpc_data = []
for record in german_patents:
    cpc_field = record.get('cpc', '[]')
    if cpc_field and cpc_field != '[]':
        try:
            cpc_list = json.loads(cpc_field)
            for item in cpc_list:
                full_code = item.get('code', '')
                if full_code and '/' in full_code:
                    # Extract level 4 (first 6 characters before slash)
                    main_group = full_code.split('/')[0]
                    level4_code = main_group[:6]
                    cpc_data.append({
                        'level4': level4_code,
                        'full_code': full_code,
                        'year': 2019
                    })
        except:
            continue

print(f"Total CPC entries: {len(cpc_data)}")

# Count patents per CPC level 4
cpc_counts = {}
full_code_map = {}
for item in cpc_data:
    code = item['level4']
    cpc_counts[code] = cpc_counts.get(code, 0) + 1
    if code not in full_code_map:
        full_code_map[code] = item['full_code']

print(f"Unique CPC level 4 groups: {len(cpc_counts)}")

# Sort by count descending and get top 20
top_cpc = sorted(cpc_counts.items(), key=lambda x: x[1], reverse=True)[:20]

# Since we only have 2019 data, EMA = count and best year = 2019
results_for_lookup = []
for level4_code, count in top_cpc:
    results_for_lookup.append({
        'cpc_level4': level4_code,
        'patent_count': count,
        'ema_2019': count,
        'best_year': 2019
    })

print("Top CPC groups prepared for title lookup")
print("CPC codes to look up:", [r['cpc_level4'] for r in results_for_lookup[:10]])

print('__RESULT__:')
print(json.dumps({
    'status': 'analysis_ready',
    'patents_analyzed': len(german_patents),
    'unique_cpc_groups': len(cpc_counts),
    'top_10_cpc': results_for_lookup[:10]
}))"}

