# Collect all patent records from previous queries
all_records = []
for var_name in all_vars:
    if 'query_db' in var_name:
        try:
            var_value = locals()[var_name]
            if isinstance(var_value, list):
                all_records.extend(var_value)
                print(f"Added {len(var_value)} records from variable")
            elif isinstance(var_value, str) and '.json' in var_value:
                import os
                if os.path.exists(var_value):
                    with open(var_value, 'r') as f:
                        file_data = json.load(f)
                    all_records.extend(file_data)
                    print(f"Added {len(file_data)} records from file")
        except:
            continue

print(f"Total patent records: {len(all_records)}")

# Extract German patents from second half 2019
german_patents = []
for record in all_records:
    try:
        patents_info = record.get('Patents_info', '')
        grant_date = record.get('grant_date', '')
        if patents_info and 'DE-' in patents_info and grant_date and '2019' in grant_date:
            date_lower = grant_date.lower()
            if any(month in date_lower for month in ['jul', 'july', 'aug', 'august', 'sep', 'september', 'oct', 'october', 'nov', 'november', 'dec', 'december']):
                german_patents.append(record)
    except:
        continue

print(f"German patents in second half 2019: {len(german_patents)}")

# Extract CPC level 4 codes and count
cpc_counts = {}
cpc_full_map = {}

for record in german_patents:
    cpc_field = record.get('cpc', '')
    if cpc_field and cpc_field != '[]':
        try:
            cpc_list = json.loads(cpc_field)
            for item in cpc_list:
                code = item.get('code', '')
                if code and '/' in code:
                    main_group = code.split('/')[0]
                    level4 = main_group[:6] if len(main_group) >= 6 else main_group
                    cpc_counts[level4] = cpc_counts.get(level4, 0) + 1
                    if level4 not in cpc_full_map:
                        cpc_full_map[level4] = code
        except:
